1	const BASE_PRICES: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	
10	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
11	const FIXED_FEE = 5;
12	const ALIKE_COMPONENT_BLOCK_SIZE = 3;
13	const ALIKE_COMPONENT_BLOCK_PRICE = 60;
14	
15	function applyFirstInsuranceSurcharge(amount: number): number {
16	  return Math.ceil((amount * (100 + FIRST_INSURANCE_SURCHARGE_PERCENT)) / 100);
17	}
18	
19	function isAlikeComponentBlock(items: { type: string }[]): boolean {
20	  return (
21	    items.length === ALIKE_COMPONENT_BLOCK_SIZE &&
22	    items.every((item) => item.type === items[0].type)
23	  );
24	}
25	
26	function quoteBasePrice(items: { type: string }[]): number {
27	  if (isAlikeComponentBlock(items)) {
28	    return ALIKE_COMPONENT_BLOCK_PRICE;
29	  }
30	  return items.reduce((sum, item) => sum + BASE_PRICES[item.type], 0);
31	}
32	
33	export function runScenario(scenario: any): unknown {
34	  const items = scenario.steps[0].items;
35	  const basePrice = quoteBasePrice(items);
36	  const premium = applyFirstInsuranceSurcharge(basePrice) + FIXED_FEE;
37	  return { results: [{ premium }] };
38	}
39

